  64 |       for (const r of results) {
  65 |         const existing = merged.get(r.observation.id);
  66 |         if (!existing || r.combinedScore > existing.combinedScore) {
  67 |           merged.set(r.observation.id, r);
  68 |         }
  69 |       }
  70 |     }
  71 | 
  72 |     return Array.from(merged.values())
  73 |       .sort((a, b) => b.combinedScore - a.combinedScore)
  74 |       .slice(0, limit);
  75 |   }
